from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about an athlete into a fluent sentence."""
    if not triples:
        return ""

    sentences = []
    for t in triples:
        s, p, o = t.subject, t.predicate, t.object

        # Simple natural‑language templates for common predicates
        if p == "birthDate":
            txt = f"{s} was born on {o}"
        elif p == "birthYear":
            txt = f"{s} was born in {o}"
        elif p == "birthPlace":
            txt = f"{s} was born in {o}"
        elif p == "height":
            txt = f"{s} is {o} metres tall"
        elif p == "weight":
            txt = f"{s} weighs {o}"
        elif p == "club" or p == "currentteam":
            txt = f"{s} plays for {o}"
        elif p == "formerTeam":
            txt = f"{s} formerly played for {o}"
        elif p == "position":
            txt = f"{s} plays in the {o} position"
        elif p == "league":
            txt = f"{s} competes in the {o} league"
        elif p == "manager":
            txt = f"{s} is managed by {o}"
        elif p == "ground":
            txt = f"{s}'s home ground is {o}"
        elif p == "draftYear":
            txt = f"{s} was drafted in {o}"
        elif p == "draftRound":
            txt = f"{s} was selected in round {o}"
        elif p == "draftPick":
            txt = f"{s} was the {o}th pick"
        elif p == "college":
            txt = f"{s} attended {o}"
        elif p == "youthclub":
            txt = f"{s} started at youth club {o}"
        elif p == "currentclub":
            txt = f"{s} currently plays for {o}"
        else:
            # Fallback generic rendering
            txt = f"{s} {p} {o}"
        sentences.append(txt)

    # Join multiple clauses into one readable sentence
    if len(sentences) == 1:
        return sentences[0] + "."
    else:
        return "; ".join(sentences) + "."

# EVOLVE-BLOCK-END

